import { NextResponse, type NextRequest } from "next/server";

const configuredBasePath = process.env.NEXT_PUBLIC_BASE_PATH ?? "";
const basePath =
  configuredBasePath && configuredBasePath !== "/"
    ? `/${configuredBasePath.replace(/^\/+|\/+$/g, "")}`
    : "";
const protectedPrefixes = ["/dashboard", "/interns", "/documents", "/advocate", "/applicants", "/bgv", "/system"];

function withBasePath(pathname: string) {
  return basePath ? `${basePath}${pathname}` : pathname;
}

function withoutBasePath(pathname: string) {
  if (!basePath) return pathname;
  if (pathname === basePath) return "/";
  return pathname.startsWith(`${basePath}/`) ? pathname.slice(basePath.length) : pathname;
}

export function proxy(request: NextRequest) {
  const token = request.cookies.get("internflow_token")?.value;
  const { pathname } = request.nextUrl;
  const logicalPathname = withoutBasePath(pathname);
  const isProtected = protectedPrefixes.some((prefix) => logicalPathname.startsWith(prefix));

  if (isProtected && !token) {
    const loginUrl = new URL(withBasePath("/login"), request.url);
    loginUrl.searchParams.set("next", logicalPathname);
    return NextResponse.redirect(loginUrl);
  }

  if (logicalPathname === "/login" && token) {
    return NextResponse.redirect(new URL(withBasePath("/dashboard"), request.url));
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    "/dashboard/:path*",
    "/interns/:path*",
    "/documents/:path*",
    "/advocate/:path*",
    "/advocate",
    "/applicants/:path*",
    "/bgv/:path*",
    "/system/:path*",
    "/login"
  ]
};
